import React, { useEffect, useMemo, useRef, useState } from "react";
import {
    Button,
    Card,
    Col,
    Divider,
    Flex,
    Form,
    Input,
    Row,
    Select,
    Space,
    Typography,
    message,
} from "antd";
import {
    SaveOutlined,
    PlusOutlined,
    DeleteOutlined,
    AudioOutlined,
    BookOutlined,
} from "@ant-design/icons";
import { Link, useNavigate, useParams } from "react-router-dom";

import {
    hrmCreateSop,
    hrmGetSopById,
    hrmUpdateSop,
} from "../../../Api/index";
import { requestHandler } from "../../../Utils/index";

const { Title, Text } = Typography;
const { TextArea } = Input;

type StepItem = {
    id: number;
    name: string;
    items: string[];
};

type SopPayload = {
    title: string;
    description?: string;
    category: string;
    status: string;
    difficultyLevel: string;
    estimatedTime: string;
    owner?: string;
    steps?: StepItem[];
};

const CATEGORIES = ["Cleaning", "Kitchen", "Maintenance", "Purchase", "Others"];
const STATUSES = ["Active", "Review", "Draft"];
const DIFFICULTIES = ["Easy", "Medium", "Hard"];
const ESTIMATED_TIMES = ["15 min", "30 min", "45 min", "1 hr", "2 hr", "3 hr"];

export default function CreateSop() {
    const { id, orgId } = useParams();
    const isEditMode = Boolean(id);
    const navigate = useNavigate();

    const [loading, setLoading] = useState(false);
    const [form] = Form.useForm<SopPayload>();

    // Steps state
    const [steps, setSteps] = useState<StepItem[]>([
        { id: 1, name: "", items: [""] },
    ]);

    // Voice note
    const [isRecording, setIsRecording] = useState(false);
    const [recordingSec, setRecordingSec] = useState(0);
    const timerRef = useRef<number | null>(null);
    const [audioURL, setAudioURL] = useState<string | null>(null);
    const [audioBlob, setAudioBlob] = useState<Blob | null>(null);
    const mediaRecorderRef = useRef<MediaRecorder | null>(null);
    const audioChunksRef = useRef<Blob[]>([]);

    const formatTime = (seconds: number) => {
        const m = Math.floor(seconds / 60);
        const s = seconds % 60;
        return `${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
    };

    const loadSop = (sopId: string) => {
        requestHandler(
            () => hrmGetSopById(sopId) as any,
            setLoading,
            (data: any) => {
                const sop = data?.data;
                form.setFieldsValue({
                    title: sop?.title ?? "",
                    description: sop?.description ?? "",
                    category: sop?.category ?? "",
                    status: sop?.status ?? "Active",
                    difficultyLevel: sop?.difficultyLevel ?? "Easy",
                    estimatedTime: sop?.estimatedTime ?? "30 min",
                });
                if (sop?.steps && Array.isArray(sop.steps) && sop.steps.length > 0) {
                    setSteps(sop.steps.map((s: any, idx: number) => ({
                        id: s.id ?? idx + 1,
                        name: s.name ?? "",
                        items: Array.isArray(s.items) && s.items.length > 0 ? s.items : [""],
                    })));
                }
                if (sop?.voiceNote) {
                    setAudioURL(sop.voiceNote);
                }
            },
            (err) => message.error(err)
        );
    };

    useEffect(() => {
        if (isEditMode && id) loadSop(id);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [id]);

    // ── Steps helpers ──────────────────────────────────────────────
    const addStep = () => {
        setSteps((prev) => [
            ...prev,
            { id: prev.length + 1, name: "", items: [""] },
        ]);
    };

    const removeStep = (idx: number) => {
        setSteps((prev) => prev.filter((_, i) => i !== idx));
    };

    const updateStepName = (idx: number, name: string) => {
        setSteps((prev) => prev.map((s, i) => (i === idx ? { ...s, name } : s)));
    };

    const addItem = (stepIdx: number) => {
        setSteps((prev) =>
            prev.map((s, i) =>
                i === stepIdx ? { ...s, items: [...s.items, ""] } : s
            )
        );
    };

    const removeItem = (stepIdx: number, itemIdx: number) => {
        setSteps((prev) =>
            prev.map((s, i) =>
                i === stepIdx
                    ? { ...s, items: s.items.filter((_, j) => j !== itemIdx) }
                    : s
            )
        );
    };

    const updateItem = (stepIdx: number, itemIdx: number, value: string) => {
        setSteps((prev) =>
            prev.map((s, i) =>
                i === stepIdx
                    ? {
                        ...s,
                        items: s.items.map((it, j) => (j === itemIdx ? value : it)),
                    }
                    : s
            )
        );
    };

    // ── Voice note ─────────────────────────────────────────────────
    const handleStartStopRecording = async () => {
        if (isRecording) {
            mediaRecorderRef.current?.stop();
            if (timerRef.current) window.clearInterval(timerRef.current);
            timerRef.current = null;
            setIsRecording(false);
            return;
        }
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const mr = new MediaRecorder(stream);
            mediaRecorderRef.current = mr;
            audioChunksRef.current = [];

            mr.ondataavailable = (e) => {
                if (e.data.size > 0) audioChunksRef.current.push(e.data);
            };

            mr.onstop = () => {
                stream.getTracks().forEach((t) => t.stop());
                const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
                setAudioBlob(blob);
                setAudioURL(URL.createObjectURL(blob));
                setRecordingSec(0);
            };

            setRecordingSec(0);
            timerRef.current = window.setInterval(
                () => setRecordingSec((p) => p + 1),
                1000
            );
            mr.start();
            setIsRecording(true);
        } catch {
            message.error("Microphone access denied.");
        }
    };

    const deleteVoiceNote = () => {
        if (audioURL?.startsWith("blob:")) URL.revokeObjectURL(audioURL);
        setAudioURL(null);
        setAudioBlob(null);
    };

    // ── Submit ─────────────────────────────────────────────────────
    const onSubmit = async () => {
        try {
            const values = await form.validateFields();

            const fd = new FormData();
            fd.append("title", values.title);
            fd.append("description", values.description || "");
            fd.append("category", values.category);
            fd.append("status", values.status);
            fd.append("difficultyLevel", values.difficultyLevel);
            fd.append("estimatedTime", values.estimatedTime);

            // Clean steps – remove empties
            const cleanSteps = steps
                .filter((s) => s.name.trim())
                .map((s, idx) => ({
                    id: idx + 1,
                    name: s.name.trim(),
                    items: s.items.filter((it) => it.trim()),
                }));
            fd.append("steps", JSON.stringify(cleanSteps));

            if (audioBlob) {
                fd.append("voiceNote", audioBlob, "voiceNote.webm");
            }

            if (isEditMode && id) {
                requestHandler(
                    () => hrmUpdateSop(id, fd) as any,
                    setLoading,
                    () => {
                        message.success("SOP updated successfully");
                        navigate(`/client/${orgId}/sop`);
                    },
                    (err) => message.error(err)
                );
            } else {
                requestHandler(
                    () => hrmCreateSop(fd) as any,
                    setLoading,
                    () => {
                        message.success("SOP created successfully");
                        navigate(`/client/${orgId}/sop`);
                    },
                    (err) => message.error(err)
                );
            }
        } catch {
            // inline validation errors
        }
    };

    return (
        <div style={{
            padding: 16, width: "100%",
        }} >
            <div style={{
                width: "100%",
                maxWidth: 1400,
                margin: "0 auto",
            }}>
                <Card style={{
                    borderRadius: 16, width: "100%",
                }} bodyStyle={{ padding: 20 }}>
                    {/* Breadcrumb + Header */}
                    <Space direction="vertical" size={2} style={{ width: "100%" }}>
                        <Space size={8}>
                            <Link to={`/client/${orgId}/sop`} style={{ textDecoration: "none" }}>
                                <Text type="secondary">SOP Management</Text>
                            </Link>
                            <Text type="secondary">›</Text>
                            <Text strong>{isEditMode ? "Edit SOP" : "Create SOP"}</Text>
                        </Space>

                        <Flex justify="space-between" align="center" wrap="wrap" gap={12}>
                            <Space>
                                <BookOutlined style={{ fontSize: 20, color: "#1677ff" }} />
                                <Title level={4} style={{ margin: 0 }}>
                                    {isEditMode ? "Edit SOP" : "Create New SOP"}
                                </Title>
                            </Space>
                            <Space>
                                <Button onClick={() => navigate(`/client/${orgId}/sop`)}>
                                    Cancel
                                </Button>
                                <Button
                                    type="primary"
                                    icon={<SaveOutlined />}
                                    onClick={onSubmit}
                                    loading={loading}
                                    style={{ borderRadius: 10 }}
                                >
                                    {isEditMode ? "Update" : "Save SOP"}
                                </Button>
                            </Space>
                        </Flex>
                    </Space>

                    <Divider style={{ margin: "14px 0" }} />

                    <Form<SopPayload>
                        form={form}
                        layout="vertical"
                        initialValues={{
                            title: "",
                            description: "",
                            category: "",
                            status: "Active",
                            difficultyLevel: "Easy",
                            estimatedTime: "30 min",
                        }}
                    >
                        <Row gutter={[14, 0]}>
                            {/* Title */}
                            <Col xs={24} md={16}>
                                <Form.Item
                                    label="SOP Title"
                                    name="title"
                                    rules={[{ required: true, message: "Title is required" }]}
                                >
                                    <Input
                                        placeholder="e.g. Kitchen Deep Cleaning Procedure"
                                        style={{ borderRadius: 10, height: 42 }}
                                    />
                                </Form.Item>
                            </Col>

                            {/* Category */}
                            <Col xs={24} md={8}>
                                <Form.Item
                                    label="Category"
                                    name="category"
                                    rules={[{ required: true, message: "Category is required" }]}
                                >
                                    <Select
                                        placeholder="Select category"
                                        style={{ borderRadius: 10 }}
                                        options={CATEGORIES.map((c) => ({ value: c, label: c }))}
                                    />
                                </Form.Item>
                            </Col>

                            {/* Status */}
                            <Col xs={24} md={8}>
                                <Form.Item label="Status" name="status">
                                    <Select
                                        style={{ borderRadius: 10 }}
                                        options={STATUSES.map((s) => ({ value: s, label: s }))}
                                    />
                                </Form.Item>
                            </Col>

                            {/* Difficulty */}
                            <Col xs={24} md={8}>
                                <Form.Item label="Difficulty Level" name="difficultyLevel">
                                    <Select
                                        style={{ borderRadius: 10 }}
                                        options={DIFFICULTIES.map((d) => ({ value: d, label: d }))}
                                    />
                                </Form.Item>
                            </Col>

                            {/* Estimated Time */}
                            <Col xs={24} md={8}>
                                <Form.Item label="Estimated Time" name="estimatedTime">
                                    <Select
                                        style={{ borderRadius: 10 }}
                                        options={ESTIMATED_TIMES.map((t) => ({ value: t, label: t }))}
                                    />
                                </Form.Item>
                            </Col>

                            {/* Description */}
                            <Col xs={24}>
                                <Form.Item label="Description" name="description">
                                    <TextArea
                                        rows={3}
                                        placeholder="Briefly describe the purpose of this SOP..."
                                        style={{ borderRadius: 10 }}
                                    />
                                </Form.Item>
                            </Col>
                        </Row>

                        {/* Steps Section */}
                        <Divider orientation="left" style={{ fontSize: 14 }}>
                            <Space>
                                <Text strong>Steps</Text>
                                <Text type="secondary" style={{ fontSize: 12 }}>
                                    ({steps.length} step{steps.length !== 1 ? "s" : ""})
                                </Text>
                            </Space>
                        </Divider>

                        <Space direction="vertical" style={{ width: "100%" }} size={12}>
                            {steps.map((step, si) => (
                                <Card
                                    key={si}
                                    size="small"
                                    style={{
                                        borderRadius: 12,
                                        border: "1px solid rgba(22,119,255,.2)",
                                        background: "rgba(22,119,255,.02)",
                                    }}
                                    title={
                                        <Flex justify="space-between" align="center">
                                            <Text strong style={{ color: "#1677ff" }}>
                                                Step {si + 1}
                                            </Text>
                                            {steps.length > 1 && (
                                                <Button
                                                    size="small"
                                                    danger
                                                    type="text"
                                                    icon={<DeleteOutlined />}
                                                    onClick={() => removeStep(si)}
                                                >
                                                    Remove
                                                </Button>
                                            )}
                                        </Flex>
                                    }
                                >
                                    <Space direction="vertical" style={{ width: "100%" }} size={8}>
                                        <Input
                                            placeholder="Step name (e.g. Prepare cleaning supplies)"
                                            value={step.name}
                                            onChange={(e) => updateStepName(si, e.target.value)}
                                            style={{ borderRadius: 8 }}
                                        />

                                        <Text type="secondary" style={{ fontSize: 12 }}>
                                            Sub-items (checklist)
                                        </Text>

                                        {step.items.map((item, ii) => (
                                            <Flex key={ii} gap={8} align="center">
                                                <Input
                                                    placeholder={`Item ${ii + 1}`}
                                                    value={item}
                                                    onChange={(e) => updateItem(si, ii, e.target.value)}
                                                    style={{ borderRadius: 8 }}
                                                />
                                                {step.items.length > 1 && (
                                                    <Button
                                                        size="small"
                                                        danger
                                                        type="text"
                                                        icon={<DeleteOutlined />}
                                                        onClick={() => removeItem(si, ii)}
                                                    />
                                                )}
                                            </Flex>
                                        ))}

                                        <Button
                                            size="small"
                                            type="dashed"
                                            icon={<PlusOutlined />}
                                            onClick={() => addItem(si)}
                                            style={{ borderRadius: 8 }}
                                        >
                                            Add Item
                                        </Button>
                                    </Space>
                                </Card>
                            ))}

                            <Button
                                type="dashed"
                                icon={<PlusOutlined />}
                                onClick={addStep}
                                style={{ width: "100%", borderRadius: 10 }}
                            >
                                Add Step
                            </Button>
                        </Space>

                        {/* Voice Note */}
                        <Divider orientation="left" style={{ fontSize: 14, marginTop: 20 }}>
                            <Text strong>Voice Note (Optional)</Text>
                        </Divider>

                        <div
                            style={{
                                border: "1px solid rgba(2,6,23,.10)",
                                borderRadius: 12,
                                padding: 14,
                                display: "flex",
                                alignItems: "center",
                                gap: 12,
                                justifyContent: "space-between",
                            }}
                        >
                            <Space direction="vertical" size={0}>
                                <Text strong>
                                    {isRecording
                                        ? "Recording..."
                                        : audioURL
                                            ? "Voice note attached"
                                            : "No voice note"}
                                </Text>
                                <Text type="secondary" style={{ fontSize: 12 }}>
                                    {isRecording
                                        ? `Time: ${formatTime(recordingSec)}`
                                        : "Tap to start/stop recording"}
                                </Text>
                            </Space>
                            <Space>
                                <Button
                                    icon={<AudioOutlined />}
                                    onClick={handleStartStopRecording}
                                    type={isRecording ? "primary" : "default"}
                                    danger={isRecording}
                                    style={{ borderRadius: 10 }}
                                >
                                    {isRecording ? "Stop" : "Record"}
                                </Button>
                                <Button
                                    icon={<DeleteOutlined />}
                                    danger
                                    disabled={!audioURL}
                                    onClick={deleteVoiceNote}
                                    style={{ borderRadius: 10 }}
                                />
                            </Space>
                        </div>

                        {audioURL && (
                            <div style={{ marginTop: 10 }}>
                                <audio controls src={audioURL} style={{ width: "100%" }} />
                            </div>
                        )}

                        <Divider style={{ margin: "18px 0" }} />

                        <Flex justify="end" gap={10} wrap="wrap">
                            <Button onClick={() => navigate(`/client/${orgId}/sop`)}>
                                Cancel
                            </Button>
                            <Button
                                type="primary"
                                icon={<SaveOutlined />}
                                onClick={onSubmit}
                                loading={loading}
                                style={{ borderRadius: 10 }}
                            >
                                {isEditMode ? "Update SOP" : "Save SOP"}
                            </Button>
                        </Flex>
                    </Form>
                </Card>
            </div>
        </div>
    );
}

import React, { useEffect, useMemo, useState } from "react";
import {
    Button,
    Card,
    Checkbox,
    Col,
    Descriptions,
    Divider,
    Drawer,
    Empty,
    Flex,
    Input,
    Modal,
    Row,
    Select,
    Skeleton,
    Space,
    Statistic,
    Table,
    Tag,
    Tooltip,
    Typography,
    message,
} from "antd";
import type { ColumnsType } from "antd/es/table";
import {
    DollarOutlined,
    CheckCircleOutlined,
    ClockCircleOutlined,
    EyeOutlined,
    SearchOutlined,
    ReloadOutlined,
    CheckOutlined,
} from "@ant-design/icons";
import dayjs from "dayjs";

import {
    hrmListSalaryRecords,
    hrmCreateSalaryRecord,
    hrmDeleteSalaryRecord,
    hrmListEmployees,
} from "../../../Api/index";
import { requestHandler } from "../../../Utils/index";

const { Title, Text } = Typography;

type SalaryRow = {
    employeeId: string;
    name: string;
    position: string;
    salary: number;
    advanceTaken: number;
    remainingSalary: number;
    salaryStatus: "Pending" | "Paid" | "Processing" | string;
    lastSalaryPaidDate?: string | null;
};

type Employee = {
    _id: string;
    displayName?: string;
    userName?: string;
    profile?: { jobRole?: string };
};

const MONTHS = [
    "January", "February", "March", "April", "May", "June",
    "July", "August", "September", "October", "November", "December",
];

const statusTag = (s?: string) => {
    if (s === "Paid") return <Tag color="green" icon={<CheckCircleOutlined />}>Paid</Tag>;
    if (s === "Processing") return <Tag color="blue" icon={<ClockCircleOutlined />}>Processing</Tag>;
    if (s === "Pending") return <Tag color="default">Pending</Tag>;
    return <Tag>{s || "-"}</Tag>;
};

const fmt = (n: number) =>
    n?.toLocaleString("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 0 }) ?? "₹0";

const fmtDate = (d?: string | null) =>
    d ? dayjs(d).format("MMM DD, YYYY") : "-";

export default function SalaryManagement() {
    const now = dayjs();
    const [selectedMonth, setSelectedMonth] = useState(now.month()); // 0-indexed
    const [selectedYear, setSelectedYear] = useState(now.year());

    const [loading, setLoading] = useState(false);
    const [salaryData, setSalaryData] = useState<SalaryRow[]>([]);

    // For bulk pay
    const [allEmployees, setAllEmployees] = useState<Employee[]>([]);
    const [payModalOpen, setPayModalOpen] = useState(false);
    const [selectedEmpIds, setSelectedEmpIds] = useState<string[]>([]);
    const [payStatus, setPayStatus] = useState<"Paid" | "Processing">("Paid");
    const [payLoading, setPayLoading] = useState(false);

    // View drawer
    const [drawerOpen, setDrawerOpen] = useState(false);
    const [activeRow, setActiveRow] = useState<SalaryRow | null>(null);

    const [q, setQ] = useState("");

    useEffect(() => {
        loadSalaryData();
        loadEmployees();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedMonth, selectedYear]);

    const loadSalaryData = () => {
        requestHandler(
            () =>
                hrmListSalaryRecords({
                    month: selectedMonth,
                    year: selectedYear,
                }) as any,
            setLoading,
            (data: any) => {
                const list = data?.data ?? data?.data?.data ?? [];
                setSalaryData(Array.isArray(list) ? list : []);
            },
            (err) => message.error(err)
        );
    };

    const loadEmployees = () => {
        requestHandler(
            () => hrmListEmployees() as any,
            null,
            (data: any) => {
                const list = data?.data?.data ?? data?.data ?? [];
                setAllEmployees(Array.isArray(list) ? list : []);
            },
            () => { }
        );
    };

    const handleBulkPay = () => {
        if (!selectedEmpIds.length) {
            message.warning("Please select at least one employee.");
            return;
        }
        requestHandler(
            () =>
                hrmCreateSalaryRecord({
                    employee: selectedEmpIds,
                    status: payStatus,
                }) as any,
            setPayLoading,
            (data: any) => {
                const skipped = data?.data?.skippedEmployees?.length ?? 0;
                const processed = (data?.data?.salaryRecords ?? []).length;
                if (skipped > 0) {
                    message.warning(
                        `Processed: ${processed}. Skipped ${skipped} already-paid employee(s).`
                    );
                } else {
                    message.success(`Salary processed for ${processed} employee(s).`);
                }
                setPayModalOpen(false);
                setSelectedEmpIds([]);
                loadSalaryData();
            },
            (err) => message.error(err)
        );
    };

    const visibleData = useMemo(() => {
        if (!q.trim()) return salaryData;
        const query = q.toLowerCase();
        return salaryData.filter(
            (r) =>
                r.name?.toLowerCase().includes(query) ||
                r.position?.toLowerCase().includes(query)
        );
    }, [salaryData, q]);

    // Summary stats
    const totalPayroll = useMemo(
        () => salaryData.reduce((acc, r) => acc + (r.salary || 0), 0),
        [salaryData]
    );
    const paidCount = useMemo(
        () => salaryData.filter((r) => r.salaryStatus === "Paid").length,
        [salaryData]
    );
    const pendingCount = useMemo(
        () => salaryData.filter((r) => r.salaryStatus === "Pending").length,
        [salaryData]
    );
    const totalAdvance = useMemo(
        () => salaryData.reduce((acc, r) => acc + (r.advanceTaken || 0), 0),
        [salaryData]
    );

    const columns: ColumnsType<SalaryRow> = [
        {
            title: "Employee",
            key: "name",
            width: 200,
            render: (_, r) => (
                <Space direction="vertical" size={0}>
                    <Text strong>{r.name || "-"}</Text>
                    <Text type="secondary" style={{ fontSize: 12 }}>
                        {r.position || "-"}
                    </Text>
                </Space>
            ),
        },
        {
            title: "Base Salary",
            dataIndex: "salary",
            key: "salary",
            width: 140,
            render: (v) => <Text strong style={{ color: "#1677ff" }}>{fmt(v)}</Text>,
        },
        {
            title: "Advance Taken",
            dataIndex: "advanceTaken",
            key: "advanceTaken",
            width: 140,
            render: (v) => (
                <Text style={{ color: v > 0 ? "#ff4d4f" : "#8c8c8c" }}>{fmt(v)}</Text>
            ),
        },
        {
            title: "Remaining Salary",
            dataIndex: "remainingSalary",
            key: "remainingSalary",
            width: 160,
            render: (v) => (
                <Text strong style={{ color: "#52c41a" }}>
                    {fmt(v)}
                </Text>
            ),
        },
        {
            title: "Status",
            dataIndex: "salaryStatus",
            key: "salaryStatus",
            width: 130,
            render: (v) => statusTag(v),
        },
        {
            title: "Last Paid",
            key: "lastPaid",
            width: 140,
            render: (_, r) => (
                <Text type="secondary">{fmtDate(r.lastSalaryPaidDate)}</Text>
            ),
        },
        {
            title: "Actions",
            key: "actions",
            fixed: "right",
            width: 100,
            render: (_, r) => (
                <Space>
                    <Tooltip title="View details">
                        <Button
                            size="small"
                            icon={<EyeOutlined />}
                            onClick={() => {
                                setActiveRow(r);
                                setDrawerOpen(true);
                            }}
                            style={{ borderRadius: 10 }}
                        />
                    </Tooltip>
                </Space>
            ),
        },
    ];

    const yearOptions = useMemo(() => {
        const years = [];
        const current = dayjs().year();
        for (let y = current - 2; y <= current + 1; y++) {
            years.push({ value: y, label: String(y) });
        }
        return years;
    }, []);

    // Employees unpaid this month
    const unpaidEmployees = useMemo(() => {
        const paidIds = new Set(
            salaryData.filter((r) => r.salaryStatus === "Paid").map((r) => r.employeeId)
        );
        return allEmployees.filter((e) => !paidIds.has(e._id));
    }, [salaryData, allEmployees]);

    return (
        <div style={{ padding: 16 }}>
            {/* Header */}
            <Card style={{ borderRadius: 16, marginBottom: 12 }}>
                <Flex justify="space-between" align="center" wrap="wrap" gap={12}>
                    <Space direction="vertical" size={2}>
                        <Space>
                            <DollarOutlined style={{ fontSize: 20, color: "#52c41a" }} />
                            <Title level={4} style={{ margin: 0 }}>
                                Salary Management
                            </Title>
                        </Space>
                        <Text type="secondary">
                            View salary summary, process payroll, and manage monthly compensation.
                        </Text>
                    </Space>

                    <Space wrap>
                        <Select
                            value={selectedMonth}
                            onChange={setSelectedMonth}
                            options={MONTHS.map((m, i) => ({ value: i, label: m }))}
                            style={{ width: 140 }}
                        />
                        <Select
                            value={selectedYear}
                            onChange={setSelectedYear}
                            options={yearOptions}
                            style={{ width: 100 }}
                        />
                        <Button
                            icon={<ReloadOutlined />}
                            onClick={loadSalaryData}
                            loading={loading}
                            style={{ borderRadius: 10 }}
                        >
                            Refresh
                        </Button>
                        <Button
                            type="primary"
                            icon={<CheckOutlined />}
                            onClick={() => setPayModalOpen(true)}
                            style={{ borderRadius: 10, background: "#52c41a", borderColor: "#52c41a" }}
                        >
                            Process Payroll
                        </Button>
                    </Space>
                </Flex>

                <Divider style={{ margin: "12px 0" }} />

                <Text type="secondary" style={{ fontSize: 13 }}>
                    Showing salary data for{" "}
                    <Text strong>
                        {MONTHS[selectedMonth]} {selectedYear}
                    </Text>
                </Text>
            </Card>

            {/* Stats */}
            <Row gutter={[12, 12]} style={{ marginBottom: 12 }}>
                <Col xs={12} sm={6}>
                    <Card style={{ borderRadius: 14, border: "1px solid #1677ff30", background: "#e6f4ff" }} bodyStyle={{ padding: "16px 20px" }}>
                        <Statistic
                            title={<Text style={{ fontSize: 12 }}>Total Payroll</Text>}
                            value={totalPayroll}
                            prefix="₹"
                            valueStyle={{ color: "#1677ff", fontSize: 22 }}
                            formatter={(v) => Number(v).toLocaleString("en-IN")}
                        />
                    </Card>
                </Col>
                <Col xs={12} sm={6}>
                    <Card style={{ borderRadius: 14, border: "1px solid #52c41a30", background: "#f6ffed" }} bodyStyle={{ padding: "16px 20px" }}>
                        <Statistic
                            title={<Text style={{ fontSize: 12 }}>Paid</Text>}
                            value={paidCount}
                            suffix={<Text type="secondary" style={{ fontSize: 13 }}>/ {salaryData.length}</Text>}
                            valueStyle={{ color: "#52c41a", fontSize: 22 }}
                        />
                    </Card>
                </Col>
                <Col xs={12} sm={6}>
                    <Card style={{ borderRadius: 14, border: "1px solid #faad1430", background: "#fffbe6" }} bodyStyle={{ padding: "16px 20px" }}>
                        <Statistic
                            title={<Text style={{ fontSize: 12 }}>Pending</Text>}
                            value={pendingCount}
                            valueStyle={{ color: "#faad14", fontSize: 22 }}
                        />
                    </Card>
                </Col>
                <Col xs={12} sm={6}>
                    <Card style={{ borderRadius: 14, border: "1px solid #ff4d4f30", background: "#fff2f0" }} bodyStyle={{ padding: "16px 20px" }}>
                        <Statistic
                            title={<Text style={{ fontSize: 12 }}>Total Advances</Text>}
                            value={totalAdvance}
                            prefix="₹"
                            valueStyle={{ color: "#ff4d4f", fontSize: 22 }}
                            formatter={(v) => Number(v).toLocaleString("en-IN")}
                        />
                    </Card>
                </Col>
            </Row>

            {/* Table */}
            <Card style={{ borderRadius: 16 }}>
                <Flex justify="space-between" align="center" wrap="wrap" gap={12} style={{ marginBottom: 14 }}>
                    <Text strong style={{ fontSize: 15 }}>
                        Employee Salary Summary
                    </Text>
                    <Input
                        value={q}
                        onChange={(e) => setQ(e.target.value)}
                        allowClear
                        prefix={<SearchOutlined />}
                        placeholder="Search by name or position..."
                        style={{ width: 260 }}
                    />
                </Flex>

                {loading ? (
                    <Space direction="vertical" style={{ width: "100%" }} size={12}>
                        <Skeleton active />
                        <Skeleton active />
                        <Skeleton active />
                    </Space>
                ) : visibleData.length === 0 ? (
                    <Empty
                        description={`No salary data for ${MONTHS[selectedMonth]} ${selectedYear}. Add employees or change the period.`}
                        image={Empty.PRESENTED_IMAGE_SIMPLE}
                    />
                ) : (
                    <Table<SalaryRow>
                        rowKey="employeeId"
                        columns={columns}
                        dataSource={visibleData}
                        pagination={false}
                        scroll={{ x: 1000 }}
                        onRow={(r) => ({
                            onDoubleClick: () => {
                                setActiveRow(r);
                                setDrawerOpen(true);
                            },
                            style: { cursor: "pointer" },
                        })}
                        rowClassName={(r) =>
                            r.salaryStatus === "Paid" ? "" : "salary-row-pending"
                        }
                    />
                )}
            </Card>

            {/* Process Payroll Modal */}
            <Modal
                title={
                    <Space>
                        <DollarOutlined style={{ color: "#52c41a" }} />
                        <Text strong>Process Payroll</Text>
                    </Space>
                }
                open={payModalOpen}
                onCancel={() => {
                    setPayModalOpen(false);
                    setSelectedEmpIds([]);
                }}
                onOk={handleBulkPay}
                confirmLoading={payLoading}
                okText="Process Salary"
                okButtonProps={{
                    style: { background: "#52c41a", borderColor: "#52c41a" },
                }}
                width={560}
            >
                <Space direction="vertical" style={{ width: "100%" }} size={14}>
                    <div>
                        <Text type="secondary" style={{ fontSize: 13 }}>
                            Processing for:{" "}
                            <Text strong>
                                {MONTHS[selectedMonth]} {selectedYear}
                            </Text>
                        </Text>
                    </div>

                    <div>
                        <Flex justify="space-between" align="center" style={{ marginBottom: 8 }}>
                            <Text strong>Payment Status</Text>
                        </Flex>
                        <Select
                            value={payStatus}
                            onChange={(v) => setPayStatus(v as any)}
                            style={{ width: "100%" }}
                            options={[
                                { value: "Paid", label: "Mark as Paid" },
                                { value: "Processing", label: "Mark as Processing" },
                            ]}
                        />
                    </div>

                    <div>
                        <Flex justify="space-between" align="center" style={{ marginBottom: 8 }}>
                            <Text strong>
                                Select Employees{" "}
                                <Text type="secondary" style={{ fontWeight: 400 }}>
                                    ({unpaidEmployees.length} unpaid this month)
                                </Text>
                            </Text>
                            <Button
                                size="small"
                                type="link"
                                onClick={() =>
                                    setSelectedEmpIds(
                                        selectedEmpIds.length === unpaidEmployees.length
                                            ? []
                                            : unpaidEmployees.map((e) => e._id)
                                    )
                                }
                            >
                                {selectedEmpIds.length === unpaidEmployees.length
                                    ? "Deselect All"
                                    : "Select All"}
                            </Button>
                        </Flex>

                        {unpaidEmployees.length === 0 ? (
                            <Text type="secondary" style={{ fontStyle: "italic" }}>
                                All employees have been paid this month. 🎉
                            </Text>
                        ) : (
                            <div
                                style={{
                                    maxHeight: 260,
                                    overflowY: "auto",
                                    border: "1px solid rgba(2,6,23,.08)",
                                    borderRadius: 10,
                                    padding: 10,
                                }}
                            >
                                <Checkbox.Group
                                    value={selectedEmpIds}
                                    onChange={(v) => setSelectedEmpIds(v as string[])}
                                    style={{ width: "100%" }}
                                >
                                    <Row gutter={[0, 6]}>
                                        {unpaidEmployees.map((emp) => (
                                            <Col span={24} key={emp._id}>
                                                <Checkbox value={emp._id}>
                                                    <Text>
                                                        {emp.displayName || emp.userName}
                                                    </Text>
                                                    {emp.profile?.jobRole && (
                                                        <Text type="secondary" style={{ marginLeft: 6, fontSize: 12 }}>
                                                            ({emp.profile.jobRole})
                                                        </Text>
                                                    )}
                                                </Checkbox>
                                            </Col>
                                        ))}
                                    </Row>
                                </Checkbox.Group>
                            </div>
                        )}
                    </div>

                    {selectedEmpIds.length > 0 && (
                        <Card
                            size="small"
                            style={{
                                borderRadius: 10,
                                background: "#f6ffed",
                                border: "1px solid #b7eb8f",
                            }}
                        >
                            <Text>
                                <CheckCircleOutlined style={{ color: "#52c41a", marginRight: 6 }} />
                                <Text strong>{selectedEmpIds.length}</Text> employee(s) selected for{" "}
                                <Text strong>{payStatus}</Text> status.
                            </Text>
                        </Card>
                    )}
                </Space>
            </Modal>

            {/* View Drawer */}
            <Drawer
                open={drawerOpen}
                onClose={() => setDrawerOpen(false)}
                width={480}
                title={
                    <Space direction="vertical" size={2}>
                        <Text type="secondary" style={{ fontSize: 12 }}>
                            Salary Details
                        </Text>
                        <Text strong style={{ fontSize: 16 }}>
                            {activeRow?.name || "-"}
                        </Text>
                    </Space>
                }
            >
                {!activeRow ? (
                    <Empty description="No record selected" />
                ) : (
                    <Space direction="vertical" size={16} style={{ width: "100%" }}>
                        <Descriptions bordered size="small" column={1} styles={{ content: { background: "#fff" } }}>
                            <Descriptions.Item label="Employee">
                                <Text strong>{activeRow.name}</Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="Position">
                                <Tag color="blue">{activeRow.position || "-"}</Tag>
                            </Descriptions.Item>
                            <Descriptions.Item label="Month">
                                <Text>
                                    {MONTHS[selectedMonth]} {selectedYear}
                                </Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="Base Salary">
                                <Text strong style={{ color: "#1677ff" }}>
                                    {fmt(activeRow.salary)}
                                </Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="Advance Taken">
                                <Text style={{ color: "#ff4d4f" }}>
                                    {fmt(activeRow.advanceTaken)}
                                </Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="Remaining Salary">
                                <Text strong style={{ color: "#52c41a" }}>
                                    {fmt(activeRow.remainingSalary)}
                                </Text>
                            </Descriptions.Item>
                            <Descriptions.Item label="Salary Status">
                                {statusTag(activeRow.salaryStatus)}
                            </Descriptions.Item>
                            <Descriptions.Item label="Last Paid Date">
                                {fmtDate(activeRow.lastSalaryPaidDate)}
                            </Descriptions.Item>
                        </Descriptions>

                        {/* Deduction Breakdown */}
                        <Card
                            size="small"
                            style={{ borderRadius: 12, background: "#fafafa" }}
                            title={<Text strong style={{ fontSize: 13 }}>Breakdown</Text>}
                        >
                            <Flex justify="space-between" style={{ padding: "4px 0" }}>
                                <Text type="secondary">Base Salary</Text>
                                <Text>{fmt(activeRow.salary)}</Text>
                            </Flex>
                            <Divider style={{ margin: "6px 0" }} />
                            <Flex justify="space-between" style={{ padding: "4px 0" }}>
                                <Text type="secondary">Advance Deduction</Text>
                                <Text style={{ color: "#ff4d4f" }}>- {fmt(activeRow.advanceTaken)}</Text>
                            </Flex>
                            <Divider style={{ margin: "6px 0" }} />
                            <Flex justify="space-between" style={{ padding: "4px 0" }}>
                                <Text strong>Net Payable</Text>
                                <Text strong style={{ color: "#52c41a", fontSize: 15 }}>
                                    {fmt(activeRow.remainingSalary)}
                                </Text>
                            </Flex>
                        </Card>
                    </Space>
                )}
            </Drawer>
        </div>
    );
}
